      box-shadow: 0 4px 20px rgba(0,0,0,0.05);
    }
    .header {
      background-color: #ef4444;
      color: #ffffff;
      padding: 20px 25px;
      text-align: left;
    }
    .header h1 {
      margin: 0;
      font-size: 20px;
      letter-spacing: 0.5px;
    }
    .content {
      padding: 25px;
      font-size: 15px;
      line-height: 1.6;
    }
    .order-table {
      width: 100%;
      border-collapse: collapse;
      margin: 18px 0;
    }
    .order-table th, .order-table td {
      border: 1px solid #e5e7eb;
      padding: 10px 12px;
      text-align: left;
      font-size: 14px;
    }
    .order-table th {
      background-color: #f3f4f6;
      font-weight: bold;
    }
    .footer {
      background-color: #fafafa;
      color: #777777;
      font-size: 12px;
      padding: 15px 25px;
      border-top: 1px solid #ececec;
      text-align: center;
    }
  </style>
</head>
<body>
  <div class="wrapper">
    <div class="container">

      <!-- Header -->
      <div class="header">
        <h1>Re-Order Request – Low Stock Alert</h1>
      </div>

      <!-- Content -->
      <div class="content">
        <p>Dear <strong>Distributor</strong>,</p>

        <p>
          We would like to inform you that the following products have reached 
          <strong>low stock levels</strong> in our inventory.  
          To avoid any shortage in supply, we request you to process the 
          <strong>re-order</strong> for the items listed below:
        </p>

        <!-- Table -->
        <table class="order-table">
          <thead>
            <tr>
              <th>Product ID</th>
              <th>Product Name</th>
              <th>Size</th>
              <th>Category</th>
              <th>Current Stock</th>
           </tr>
          </thead>
          <tbody>
             <th>{{ $('Stock Register').item.json.product_id }}</th>
              <th>{{ $('Stock Register').item.json.product_name }}</th>
              <th>{{ $('Stock Register').item.json.size }}</th>
              <th>{{ $('Stock Register').item.json.category }}</th>
              <th>{{ $('Stock Register').item.json.current_stock }}</th>
          </tbody>
        </table>

        <p>
          Kindly confirm the expected delivery timeline so we can coordinate distribution accordingly.
        </p>

        <p>Thank you for your cooperation.</p>

        <p>Best regards,<br>
          <strong>Nestle Distribution Multan</strong><br>
        </p>
      </div>

      <!-- Footer -->
      <div class="footer">
        This message is intended only for the supplier of Nestle Distribution Multan.
      </div>

    </div>
  </div>
</body>
</html>
